'use strict';
        const { useState, useEffect, useMemo, useRef, useCallback, useContext } = React;
        // Build version source of truth for the app shell. Every shipped change should bump this:
        // 1) Update MASTER_BUILD_VERSION below to the new value.
        // 2) Mirror it into Firestore so live clients see the update banner:
        //    npx firebase firestore:documents:update settings/app buildVersion=<NEW_VERSION> --project the-gaffer-581d8
        const MASTER_BUILD_VERSION = '2026.03.14-73';
        if (!window.GAFFER_BUILD_VERSION) {
            window.GAFFER_BUILD_VERSION = MASTER_BUILD_VERSION;
        }
        const APP_VERSION = window.GAFFER_BUILD_VERSION;
        const READ_ONLY = !!window.GAFFER_READ_ONLY;
        const VERSION_STORAGE_KEY = 'gaffer:lastBuildVersion';
        const LAST_BACKUP_AT_KEY = 'gaffer:lastBackupAt';
        const FOCUS_FIXTURE_BACK_TAB_KEY = 'gaffer:focusFixtureBackTab';
        console.info('[Gaffer] Loaded build version:', APP_VERSION);

        // --- 1. Database & Domain Models (Firestore) ---
        if (!window.db) {
            throw new Error('Firebase is not initialized. Set window.GAFFER_FIREBASE_CONFIG with real project keys before loading this page.');
        }
        const db = window.db;
        const waitForDb = () => window.firebaseReady;

        // --- 2. Shared Logic ---
        const parseCurrency = (str) => {
            if (!str) return 0;
            let clean = str.replace(/[−–]/g, '-').replace(/[^0-9.-]/g, '');
            return parseFloat(clean) || 0;
        };

        const deriveFlow = (type) => type === 'INCOME' ? 'receivable' : 'payable';
        const FORFEIT_RESULT = Object.freeze({
            NONE: 'NONE',
            OPPOSITION: 'OPPOSITION_FORFEIT',
            OURS: 'OUR_FORFEIT'
        });

        const PLAYER_FEE_CATEGORY = 'Player Fee';
        const PITCH_FEE_CATEGORY = 'Pitch Fee';
        const LEDGER_REPAIR_FLAG_KEY = 'gaffer:ledgerRepairV1Done';
        const PLAYER_RECON_REPAIR_FLAG_KEY = 'gaffer:playerReconciliationV1Done';
        const PLAYER_NAME_MATCH_HISTORY_MAX_NAMES = 500;
        const PLAYER_NAME_MATCH_HISTORY_MAX_PLAYERS_PER_NAME = 6;

        const normalizePersonNameKey = (name = '') => {
            return (name || '')
                .toString()
                .toLowerCase()
                .replace(/\s+/g, ' ')
                .trim();
        };

        const normalizeFeeCategory = (value = '') => {
            if (!value) return '';
            const raw = value.toString().trim();
            if (!raw) return '';
            const upper = raw.toUpperCase();
            if (upper === 'MATCH_FEE' || upper === 'PLAYER_FEE' || upper === 'PLAYER FEE') return PLAYER_FEE_CATEGORY;
            if (upper === 'MATCH FEE' || upper === 'PITCH_FEE' || upper === 'PITCH FEE') return PITCH_FEE_CATEGORY;
            return raw;
        };

        const normalizeFeeCategoryForMigration = (value = '', playerId = null) => {
            if (!value) return '';
            const raw = value.toString().trim();
            if (!raw) return '';
            const upper = raw.toUpperCase();
            if (upper === 'MATCH FEE' && playerId !== undefined && playerId !== null) {
                return PLAYER_FEE_CATEGORY;
            }
            return normalizeFeeCategory(raw);
        };

        const isPlayerFeeCategory = (value = '') => normalizeFeeCategory(value) === PLAYER_FEE_CATEGORY;

        const inferFlowFromAmount = (amount = 0, fallbackType = '') => {
            const numeric = Number(amount || 0);
            if (numeric > 0) return 'receivable';
            if (numeric < 0) return 'payable';
            return deriveFlow(fallbackType);
        };

        const normalizeForfeitResult = (value = '') => {
            const clean = (value || '').toString().trim().toUpperCase();
            if (clean === FORFEIT_RESULT.OPPOSITION || clean === 'OPPOSITION' || clean === 'OPPOSITION_FORFEIT') {
                return FORFEIT_RESULT.OPPOSITION;
            }
            if (clean === FORFEIT_RESULT.OURS || clean === 'OUR' || clean === 'OURS' || clean === 'OUR_FORFEIT') {
                return FORFEIT_RESULT.OURS;
            }
            return FORFEIT_RESULT.NONE;
        };

        const getFixtureForfeitLabel = (fixture = {}) => {
            const forfeit = normalizeForfeitResult(fixture?.forfeitResult);
            if (forfeit === FORFEIT_RESULT.OPPOSITION) return 'Opposition forfeited';
            if (forfeit === FORFEIT_RESULT.OURS) return 'We forfeited';
            return '';
        };

        const getFixtureOutcome = (fixture = {}) => {
            const forfeit = normalizeForfeitResult(fixture?.forfeitResult);
            if (forfeit === FORFEIT_RESULT.OPPOSITION) {
                return { played: true, result: 'W', points: 3, isForfeit: true };
            }
            if (forfeit === FORFEIT_RESULT.OURS) {
                return { played: true, result: 'L', points: 0, isForfeit: true };
            }
            const hasScore = typeof fixture?.homeScore === 'number' && typeof fixture?.awayScore === 'number';
            if (!hasScore) {
                if (fixture?.status === 'PLAYED') {
                    return { played: true, result: 'D', points: 1, isForfeit: false };
                }
                return { played: false, result: '', points: 0, isForfeit: false };
            }
            const our = Number(fixture.homeScore || 0);
            const their = Number(fixture.awayScore || 0);
            if (our > their) return { played: true, result: 'W', points: 3, isForfeit: false };
            if (our === their) return { played: true, result: 'D', points: 1, isForfeit: false };
            return { played: true, result: 'L', points: 0, isForfeit: false };
        };

        const getSettlementActionLabel = (tx, settled = false) => {
            const isReceivable = tx?.flow === 'receivable' || tx?.type === 'INCOME' || Number(tx?.amount || 0) > 0;
            if (isReceivable) return settled ? 'Received' : 'Mark received';
            return settled ? 'Paid' : 'Mark paid';
        };

        const formatCurrency = (value, options = {}) => {
            const amount = Number(value || 0);
            try {
                return amount.toLocaleString('en-SG', { style: 'currency', currency: 'SGD', ...options });
            } catch (e) {
                return `S$${amount.toFixed(options.minimumFractionDigits || 0)}`;
            }
        };

        const formatBuildLabel = (version, isViewer = false) => {
            const raw = (version || '').toString().trim();
            if (!raw && isViewer) return 'viewer';
            let withoutPrefix = raw.replace(/^v+/i, '');
            if (isViewer) {
                const lower = withoutPrefix.toLowerCase();
                if (lower.startsWith('viewer-')) {
                    withoutPrefix = withoutPrefix.slice(withoutPrefix.indexOf('-') + 1);
                }
                return {
                    label: 'viewer',
                    version: withoutPrefix || 'latest'
                };
            }
            return {
                label: `Build ${withoutPrefix || 'latest'}`,
                version: ''
            };
        };

        const setFixtureFocusContext = ({ fixtureId = null, opponent = '', venue = '', backTab = '' } = {}) => {
            try {
                if (fixtureId !== undefined && fixtureId !== null && String(fixtureId).trim()) {
                    localStorage.setItem('gaffer:focusFixtureId', String(fixtureId));
                }
                if (opponent) localStorage.setItem('gaffer:focusFixtureOpponent', opponent);
                if (venue) localStorage.setItem('gaffer:focusFixtureVenue', venue);
                if (backTab) localStorage.setItem(FOCUS_FIXTURE_BACK_TAB_KEY, backTab);
                else localStorage.removeItem(FOCUS_FIXTURE_BACK_TAB_KEY);
            } catch (err) {
                console.warn('Unable to persist fixture focus context', err);
            }
        };
        const performHardPwaRefresh = async () => {
            if (typeof navigator !== 'undefined' && 'serviceWorker' in navigator) {
                const registrations = await navigator.serviceWorker.getRegistrations();
                await Promise.all(registrations.map(reg => reg.unregister().catch(() => false)));
            }
            if (typeof caches !== 'undefined' && caches.keys) {
                const cacheNames = await caches.keys();
                await Promise.all(cacheNames.map(name => caches.delete(name).catch(() => false)));
            }
            try {
                localStorage.removeItem(VERSION_STORAGE_KEY);
            } catch (err) {
                // localStorage may be unavailable in some contexts.
            }
            const url = new URL(window.location.href);
            url.searchParams.set('refresh', String(Date.now()));
            window.location.replace(url.toString());
        };
        const openPrintDocument = (docHtml = '', options = {}) => {
            const title = (options?.title || 'Print View').toString();
            if (typeof window === 'undefined' || typeof document === 'undefined' || !docHtml) return false;
            try {
                const blob = new Blob([docHtml], { type: 'text/html;charset=utf-8' });
                const blobUrl = URL.createObjectURL(blob);
                const iframe = document.createElement('iframe');
                iframe.setAttribute('title', title);
                iframe.setAttribute('aria-hidden', 'true');
                iframe.style.position = 'fixed';
                iframe.style.right = '0';
                iframe.style.bottom = '0';
                iframe.style.width = '0';
                iframe.style.height = '0';
                iframe.style.border = '0';
                iframe.style.opacity = '0';
                iframe.style.pointerEvents = 'none';
                let cleaned = false;
                const cleanup = () => {
                    if (cleaned) return;
                    cleaned = true;
                    window.setTimeout(() => {
                        if (iframe.parentNode) iframe.parentNode.removeChild(iframe);
                        URL.revokeObjectURL(blobUrl);
                    }, 0);
                };
                iframe.onload = () => {
                    const frameWindow = iframe.contentWindow;
                    if (!frameWindow) {
                        cleanup();
                        return;
                    }
                    const afterPrint = () => {
                        try {
                            frameWindow.removeEventListener('afterprint', afterPrint);
                        } catch (err) {
                            // ignore
                        }
                        cleanup();
                    };
                    try {
                        frameWindow.addEventListener('afterprint', afterPrint);
                    } catch (err) {
                        // ignore
                    }
                    window.setTimeout(() => {
                        try {
                            frameWindow.focus();
                            frameWindow.print();
                        } catch (err) {
                            cleanup();
                        }
                        window.setTimeout(cleanup, 60000);
                    }, 200);
                };
                iframe.src = blobUrl;
                document.body.appendChild(iframe);
                return true;
            } catch (err) {
                try {
                    const printWindow = window.open('', '_blank', 'noopener,noreferrer');
                    if (!printWindow) return false;
                    printWindow.document.write(docHtml);
                    printWindow.document.close();
                    printWindow.focus();
                    window.setTimeout(() => {
                        try {
                            printWindow.print();
                        } catch (printErr) {
                            // ignore
                        }
                    }, 250);
                    return true;
                } catch (popupErr) {
                    return false;
                }
            }
        };
